  1→import React, { useState, useRef, useCallback, useEffect } from 'react';
  2→import ReactionPicker from './ReactionPicker';
  3→import { getReactionEmoji } from '../../utils/reactionConfig';
  4→import './reactions.css';
  5→
  6→const ReactionButton = ({ userReaction, reactionCount, onReact, disabled }) => {
  7→    const [showPicker, setShowPicker] = useState(false);
  8→    const hoverTimerRef = useRef(null);
  9→    const leaveTimerRef = useRef(null);
 10→    const longPressTimerRef = useRef(null);
 11→    const longPressOpenedRef = useRef(false);
 12→    const containerRef = useRef(null);
 13→
 14→    const handleMouseEnter = useCallback(() => {
 15→        if (leaveTimerRef.current) {
 16→            clearTimeout(leaveTimerRef.current);
 17→            leaveTimerRef.current = null;
 18→        }
 19→        hoverTimerRef.current = setTimeout(() => {
 20→            setShowPicker(true);
 21→        }, 300);
 22→    }, []);
 23→
 24→    const handleMouseLeave = useCallback(() => {
 25→        if (hoverTimerRef.current) {
 26→            clearTimeout(hoverTimerRef.current);
 27→            hoverTimerRef.current = null;
 28→        }
 29→        leaveTimerRef.current = setTimeout(() => {
 30→            setShowPicker(false);
 31→        }, 150);
 32→    }, []);
 33→
 34→    const handleTouchStart = useCallback(() => {
 35→        longPressTimerRef.current = setTimeout(() => {
 36→            longPressOpenedRef.current = true;
 37→            setShowPicker(true);
 38→        }, 500);
 39→    }, []);
 40→
 41→    const handleTouchEnd = useCallback(() => {
 42→        if (longPressTimerRef.current) {
 43→            clearTimeout(longPressTimerRef.current);
 44→            longPressTimerRef.current = null;
 45→        }
 46→    }, []);
 47→
 48→    useEffect(() => {
 49→        return () => {
 50→            if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
 51→            if (leaveTimerRef.current) clearTimeout(leaveTimerRef.current);
 52→            if (longPressTimerRef.current) clearTimeout(longPressTimerRef.current);
 53→        };
 54→    }, []);
 55→
 56→    const handleQuickClick = useCallback((e) => {
 57→        e.preventDefault();
 58→        e.stopPropagation();
 59→        if (disabled) return;
 60→
 61→        if (longPressOpenedRef.current) {
 62→            longPressOpenedRef.current = false;
 63→            return;
 64→        }
 65→
 66→        if (showPicker) {
 67→            setShowPicker(false);
 68→            return;
 69→        }
 70→
 71→        // Quick tap: toggle heart (or remove current reaction)
 72→        if (userReaction) {
 73→            onReact(userReaction); // toggle off
 74→        } else {
 75→            onReact('heart'); // default to heart
 76→        }
 77→    }, [userReaction, onReact, disabled, showPicker]);
 78→
 79→    const handlePickerSelect = useCallback((reactionType) => {
 80→        setShowPicker(false);
 81→        onReact(reactionType);
 82→    }, [onReact]);
 83→
 84→    const hasReaction = !!userReaction;
 85→    const displayEmoji = hasReaction ? getReactionEmoji(userReaction) : null;
 86→
 87→    return (
 88→        <div
 89→            className="reaction-button-container"
 90→            ref={containerRef}
 91→            onMouseEnter={handleMouseEnter}
 92→            onMouseLeave={handleMouseLeave}
 93→            onTouchStart={handleTouchStart}
 94→            onTouchEnd={handleTouchEnd}
 95→        >
 96→            <div
 97→                className={`reaction-button ${hasReaction ? 'has-reaction' : ''}`}
 98→                onClick={handleQuickClick}
 99→            >
100→                {hasReaction ? (
101→                    <span className="reaction-button-emoji">{displayEmoji}</span>
102→                ) : (
103→                    <svg className="svg-like" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
104→                        <g id="style=fill">
105→                        <g id="like">
106→                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M15.9977 5.63891C16.2695 4.34931 15.433 3.00969 14.2102 2.59462C13.6171 2.37633 12.9892 2.4252 12.4662 2.60499C11.9449 2.78419 11.4461 3.12142 11.1369 3.58441L11.136 3.58573L7.49506 9.00272C8.05104 9.29585 8.43005 9.87954 8.43005 10.5518V21.3018H6.91003V21.3018H16.6801C18.2938 21.3018 19.2028 20.2977 19.8943 19.202C20.6524 18.0009 21.1453 16.7211 21.5116 15.5812C21.6808 15.0546 21.8252 14.5503 21.9547 14.0984L21.9863 13.9881C22.126 13.5007 22.2457 13.0904 22.366 12.7549C22.698 11.8292 22.5933 10.9072 22.067 10.2072C21.5476 9.5166 20.7005 9.15175 19.76 9.15175H15.76C15.6702 9.15175 15.6017 9.11544 15.5599 9.06803C15.5238 9.02716 15.4831 8.95058 15.502 8.81171L15.9977 5.63891Z" fill="#5e5e5eff"/>
107→                        <path id="rec" d="M2.18005 10.6199C2.18005 10.03 2.62777 9.55176 3.18005 9.55176H6.68005C7.23234 9.55176 7.68005 10.03 7.68005 10.6199V21.3018H3.18005C2.62777 21.3018 2.18005 20.8235 2.18005 20.2336V10.6199Z" fill="#5e5e5eff"/>
108→                        </g>
109→                        </g>
110→                    </svg>
111→                )}
112→            </div>
113→            {typeof reactionCount === 'number' && reactionCount > 0 && (
114→                <span className="reaction-count">{reactionCount}</span>
115→            )}
116→            <ReactionPicker
117→                isOpen={showPicker}
118→                onSelect={handlePickerSelect}
119→                currentReaction={userReaction}
120→            />
121→        </div>
122→    );
123→};
124→
125→export default ReactionButton;
