127→/**
128→ * Get detailed reactions breakdown for a post.
129→ */
130→export const getPostReactionsService = async (journalId) => {
131→    if (!journalId) {
132→        throw { status: 400, error: 'journalId is required' };
133→    }
134→
135→    const { data, error } = await supabase.rpc('get_post_reactions', {
136→        p_journal_id: journalId,
137→    });
138→
139→    if (error) {
140→        console.error('error getting post reactions:', error.message);
141→        throw { status: 500, error: 'failed to get reactions' };
142→    }
143→
144→    return { reactions: data || [] };
145→};
